diff --git a/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js b/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js
index 1f58a28ca..4e3818d0f 100644
--- a/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js
+++ b/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js
@@ -597,6 +597,23 @@ function is_parent(path, elements) {
 	return false;
 }

+/**
+ * Checks if any ancestor element in the path matches the given element names
+ * @param {AST.SvelteNode[]} path
+ * @param {string[]} elements
+ */
+function has_ancestor(path, elements) {
+	let i = path.length;
+	while (i--) {
+		const parent = path[i];
+		if (parent.type === 'SvelteElement') return true; // unknown, play it safe, so we don't warn
+		if (parent.type === 'RegularElement' && elements.includes(parent.name)) {
+			return true;
+		}
+	}
+	return false;
+}
+
 /**
  * @param {AST.Attribute} attribute
  * @param {ARIAProperty} name
@@ -875,8 +892,13 @@ export function check_element(node, context) {
 		}

 		// no-autofocus
+		// Exception: autofocus is recommended for <dialog> and its descendants
+		// https://html.spec.whatwg.org/multipage/interactive-elements.html#the-dialog-element
 		if (name === 'autofocus') {
-			w.a11y_autofocus(attribute);
+			const is_dialog_or_in_dialog = node.name === 'dialog' || has_ancestor(context.path, ['dialog']);
+			if (!is_dialog_or_in_dialog) {
+				w.a11y_autofocus(attribute);
+			}
 		}

 		// scope
