   709→			handlers.add(attribute.name);
   710→		} else if (attribute.type === 'Attribute') {
   711→			if (is_event_attribute(attribute)) {
   712→				handlers.add(attribute.name.slice(2));
   713→			} else {
   714→				attributes.push(attribute);
   715→				attribute_map.set(attribute.name, attribute);
   716→				if (attribute.name === 'contenteditable') {
   717→					has_contenteditable_attr = true;
   718→				}
   719→			}
