   729→		// aria-props
   730→		if (name.startsWith('aria-')) {
   731→			if (invisible_elements.includes(node.name)) {
   732→				// aria-unsupported-elements
   733→				w.a11y_aria_attributes(attribute, node.name);
   734→			}
   735→
   736→			const type = name.slice(5);
   737→			if (!aria_attributes.includes(type)) {
   738→				const match = fuzzymatch(type, aria_attributes);
