   818→								w.a11y_role_has_required_aria_props(
   819→									attribute,
   820→									current_role,
   821→									list(
   822→										required_role_props.map((v) => `"${v}"`),
   823→										'and'
   824→									)
   825→								);
   826→							}
   827→						}
   828→					}
