   831→					if (
   832→						!has_spread &&
   833→						!has_disabled_attribute(attribute_map) &&
   834→						!is_hidden_from_screen_reader(node.name, attribute_map) &&
   835→						!is_presentation_role(current_role) &&
   836→						is_interactive_roles(current_role) &&
   837→						is_static_element(node.name, attribute_map) &&
   838→						!attribute_map.get('tabindex')
   839→					) {
   840→						const has_interactive_handlers = [...handlers].some((handler) =>
   841→							a11y_interactive_handlers.includes(handler)
   842→						);
